 41	import './BootableVolumeRow.scss';
 42	
 43	type BootableVolumeRowProps = {
 44	  activeColumnIDs: string[];
 45	  bootableVolume: BootableVolume;
 46	  rowData: {
 47	    bootableVolumeSelectedState: [BootableVolume, InstanceTypeVMStore['onSelectCreatedVolume']];
 48	    dataImportCron: V1beta1DataImportCron;
 49	    favorites: [isFavorite: boolean, updaterFavorites: (val: boolean) => void];
 50	    preference: V1beta1VirtualMachineClusterPreference;
 51	    pvcSource: IoK8sApiCoreV1PersistentVolumeClaim;
 52	    volumeSnapshotSource: VolumeSnapshotKind;
 53	  };
 54	};
 55	
 56	const BootableVolumeRow: FC<BootableVolumeRowProps> = ({
 57	  activeColumnIDs,
 58	  bootableVolume,
 59	  rowData: {
 60	    bootableVolumeSelectedState: [selectedBootableVolume, setSelectedBootableVolume],
 61	    dataImportCron,
 62	    favorites,
 63	    preference,
 64	    pvcSource,
 65	    volumeSnapshotSource,
 66	  },
 67	}) => {
 68	  const { t } = useKubevirtTranslation();
 69	  const bootVolumeName = getName(bootableVolume);
 70	  const bootVolumeNamespace = getNamespace(bootableVolume);
 71	  const sizeData = formatBytes(
 72	    pvcSource?.spec?.resources?.requests?.storage || getVolumeSnapshotSize(volumeSnapshotSource),
 73	  );
 74	  const icon = getVolumeNameOSIcon(bootVolumeName) || getTemplateOSIcon(preference);
 75	
 76	  const [isFavorite, addOrRemoveFavorite] = favorites;
 77	
 78	  const handleOnClick = () => {
 79	    setSelectedBootableVolume(bootableVolume, pvcSource, volumeSnapshotSource);
 80	    logITFlowEvent(BOOTABLE_VOLUME_SELECTED, null, {
 81	      selectedBootableVolume: getName(bootableVolume),
 82	    });
 83	  };
 84	
 85	  const { volumeListNamespace } = useInstanceTypeVMStore();
 86	  const isCloning =
 87	    isDataImportCronProgressing(dataImportCron) ||
 88	    isDataSourceCloning(bootableVolume as V1beta1DataSource);
 89	
 90	  return (
 91	    <Tr
 92	      isRowSelected={
 93	        getName(selectedBootableVolume) === bootVolumeName &&
 94	        getNamespace(selectedBootableVolume) === bootVolumeNamespace
 95	      }
 96	      className="bootable-volume-row"
 97	      isClickable
 98	      isSelectable
 99	      onClick={() => handleOnClick()}
100	    >
101	      <TableData
102	        favorites={{
103	          isFavorited: isFavorite,
104	          onFavorite: (e: MouseEvent, isFavoring: boolean) => {
105	            e.stopPropagation();
106	            addOrRemoveFavorite(isFavoring);
107	          },
108	        }}
109	        activeColumnIDs={activeColumnIDs}
110	        id="favorites"
111	      />
112	      <TableData activeColumnIDs={activeColumnIDs} id="name" width={20}>
113	        <img alt="os-icon" className="vm-catalog-row-icon" src={icon} />
114	        <Content className="bootable-volume-row__name--text" component={ContentVariants.small}>
115	          {bootVolumeName}
116	        </Content>
117	        {isDeprecated(bootVolumeName) && <DeprecatedBadge />}
118	        {isCloning && <Label className="vm-catalog-row-label">{t('Clone in progress')}</Label>}
119	        {isDataSourceUploading(bootableVolume as V1beta1DataSource) && (
120	          <Label className="vm-catalog-row-label">{t('Upload in progress')}</Label>
121	        )}
122	      </TableData>
123	      {volumeListNamespace === ALL_PROJECTS && (
124	        <TableData activeColumnIDs={activeColumnIDs} id="namespace" width={20}>
125	          {bootVolumeNamespace}
126	        </TableData>
127	      )}
128	      <TableData activeColumnIDs={activeColumnIDs} id="operating-system" width={20}>
129	        {preference?.metadata?.annotations?.[ANNOTATIONS.displayName] || NO_DATA_DASH}
130	      </TableData>
131	      <TableData activeColumnIDs={activeColumnIDs} id="storage-class" width={15}>
132	        {getVolumeSnapshotStorageClass(volumeSnapshotSource) ||
133	          pvcSource?.spec?.storageClassName ||
134	          NO_DATA_DASH}
135	      </TableData>
136	      <TableData activeColumnIDs={activeColumnIDs} id="size">
137	        {sizeData}
138	      </TableData>
139	      <TableData activeColumnIDs={activeColumnIDs} id={ANNOTATIONS.description} width={30}>
140	        <TableText wrapModifier={WrapModifier.truncate}>
141	          {bootableVolume?.metadata?.annotations?.[ANNOTATIONS.description] || NO_DATA_DASH}
142	        </TableText>
143	      </TableData>
144	    </Tr>
145	  );
146	};
147	
148	export default BootableVolumeRow;
